// =======================================================
// === 1. PARSE E NORMALIZAÇÃO DE DADOS ===
// =======================================================
let filtros = {};
try {
  let raw = $json.output || $json;
  if (typeof raw === 'string') {
    raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();
    filtros = JSON.parse(raw);
  } else {
    filtros = raw;
  }
} catch (e) {
  console.log('❌ Erro ao parsear filtros:', e);
  filtros = {};
}

// Helpers SQL
const escapeSql = (v) => v ? String(v).replace(/'/g, "''") : null;
const toIn = (arr) => arr.map(v => `'${escapeSql(v)}'`).join(', ');

// =======================================================
// === 1.5 FILTRO DE DEPARTAMENTO (gestor_depto) ===
// =======================================================
const departamentoId = filtros.departamento_id || null;
const departamentoNome = filtros.departamento_nome || null;


// 🚨 PRESERVA O TIPO DE GESTOR PARA OS NÓS POSTERIORES
filtros.tipo_gestor = filtros.tipo_gestor || 'gestor_full';

const filtroDepartamentoSql = departamentoId
  ? ` AND e.[department_id] = ${parseInt(departamentoId)} `
  : '';

// =======================================================
// === 2. DETECÇÃO DE INTENÇÃO & TRADUÇÃO ===
// =======================================================
const logica = (filtros.logica_aplicada || '').toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

// 🚨 DETECTORES DE MODO 🚨

// 1. Identifica se é sobre INSS ou Longa Duração
const isInssOrLonga = 
    logica.includes('inss') || 
    logica.includes('longa duracao') || 
    logica.includes('beneficio') || 
    logica.includes('b91') || 
    logica.includes('b31') || 
    logica.includes('acidente') || 
    logica.includes('cat') ||
    filtros.tipo_afastamento === 'Acidente';

// 2. Atestados (Bloco C)
// Só entra aqui se NÃO for contexto de INSS/Benefício
const isCidVinculado = (logica.includes('cid') || filtros.agrupamento?.includes('cid')) && 
                       (logica.includes('vinculado') || (logica.includes('afastamento') && !isInssOrLonga) || (logica.includes('previdencia') && !isInssOrLonga));

const isAtestado = logica.includes('atestado') || 
                   logica.includes('certificados') || 
                   logica.includes('dias de ausencia') || 
                   isCidVinculado; 

// 3. Benefícios Puro (Bloco B) - CORRIGIDO
// 🚨 MUDANÇA: Se tiver "LIMBO", "CID" ou "Doença", NÃO é benefício puro, é SAÚDE (Bloco A)
const isBeneficio = (
    (logica.includes('beneficio') || logica.includes('inss') || logica.includes('previdencia')) && 
    !logica.includes('cid') && 
    !logica.includes('doenca') &&
    !logica.includes('limbo') // 👈 O Limbo expulsa a query do Bloco B!
) || logica.includes('especie') || logica.includes('dataprev');

// 4. Afastamentos / Saúde Geral (Bloco A)
// Se não for Atestado e não for Benefício Puro, cai aqui (incluindo "CIDs do INSS")
const isAfastamento = !isAtestado && !isBeneficio && (logica.includes('afastamento') || logica.includes('ausencia') || logica.includes('absenteismo') || logica.includes('limbo') || logica.includes('alta antecipada') || logica.includes('tempo medio') || logica.includes('acidente') || logica.includes('cat') || logica.includes('contatos') || isInssOrLonga);

// 5. Exames (ASO)
const isBuscaExame = 
    logica.includes('exame') ||
    /\baso\b/.test(logica) || 
    logica.includes('retorno ao trabalho') ||
    logica.includes('periodico') ||
    logica.includes('admissional') ||
    logica.includes('demissional');

// 6. Previsão
const isPrevisao = filtros.metrica === 'previsao' || logica.includes('previsao') || logica.includes('projecao') || logica.includes('futuro');

// Se for previsão, forçamos o agrupamento por mês se ele não existir
if (isPrevisao) {
    if (!filtros.agrupamento) filtros.agrupamento = [];
    if (!filtros.agrupamento.some(a => a.toLowerCase() === 'mes')) {
        filtros.agrupamento.unshift('mes'); // Adiciona mês para criar a série temporal
    }
}

const traduzirTermo = (campo, valor) => {
    if (!valor) return valor;
    const v = String(valor).toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, ""); // Remove acentos

    if (campo === 'etapa') {
        if (v.includes('pericia') || v.includes('agendamento')) return 'steps.scheduling';
        if (v.includes('exame')) return 'steps.exam'; 
        if (v.includes('beneficio')) return 'steps.benefits';
        if (v.includes('retorno')) return 'steps.return';
    }

    if (campo === 'status') {
        if (v.includes('agendado')) {
            let etapaFiltro = filtros.etapa;
            if (Array.isArray(etapaFiltro)) etapaFiltro = etapaFiltro[0];
            const etapa = String(etapaFiltro || '').toLowerCase();

            if (etapa.includes('pericia') || etapa.includes('agendamento')) return 'Perícia';
            if (etapa.includes('exame')) return 'Exame retorno';
            return 'Agendado'; 
        }
    }
    return valor;
};

// =======================================================
// === 3. GERADOR DE WHERE DINÂMICO ===
// =======================================================
const filtroTxt = (alias, campoAgente, valor) => {
  if (!valor) return '';
  if (Array.isArray(valor) && valor.length === 0) return '';

  let valorFinal = valor;
  if (['etapa', 'status'].includes(campoAgente)) {
      if (Array.isArray(valor)) {
          valorFinal = valor.map(v => traduzirTermo(campoAgente, v));
      } else {
          valorFinal = traduzirTermo(campoAgente, valor);
      }
  }

  // A tabela user_steps já é de afastamentos, então filtrar pela palavra "Afastado" elimina CIDs reais (Doença, etc)
  if (campoAgente === 'status' && String(valorFinal).toLowerCase() === 'afastado') {
      return '';
  }

  // Trava de segurança para não quebrar a lógica de Exames/Atestados
  if (isBuscaExame || isAtestado) {
      if (campoAgente === 'etapa' && String(valorFinal).includes('steps.exam')) return ''; 
      if (campoAgente === 'status' && isBuscaExame) return ''; 
  }

  let colSql = '';
  // Mapeamentos Padrão
  if (campoAgente === 'cargo') colSql = `p.[position_name]`;
  else if (campoAgente === 'etapa') colSql = `s.[name]`; 
  else if (campoAgente === 'status') colSql = `gs.[description]`; 
  // 🚨 NOVA REGRA CID: Busca tanto pelo Código (Ex: F06.0) quanto pelo Nome (Ex: Alucinose)
  else if (campoAgente === 'cid' || campoAgente === 'cid_grupo') {
      const valStr = Array.isArray(valorFinal) ? valorFinal[0] : valorFinal;
      // Retorna a busca direta combinando os dois campos
      return ` AND (c_cid.[description] LIKE '%${escapeSql(valStr)}%' OR c_cid.[code_cid] LIKE '%${escapeSql(valStr)}%')`;
  }
  else if (campoAgente === 'sexo') colSql = `ug.[label]`;
  else if (campoAgente === 'centro_de_custo') colSql = `cc.[name]`;

  // Mapeamentos Específicos para Atestados (usando user_medical_info)
  else if (isAtestado && campoAgente === 'medico') colSql = `umi.[doctor_name]`;
    else if (campoAgente === 'colaborador') colSql = `u.[name]`;

  else if (campoAgente === 'tipo_beneficio' || campoAgente === 'especie_beneficio') {
      const valStr = Array.isArray(valorFinal) ? valorFinal[0] : valorFinal;
      return ` AND (bt.[benefit_type_description] LIKE '%${escapeSql(valStr)}%' OR bt.[benefit_type_code] IN (${toIn(Array.isArray(valorFinal)?valorFinal:[valorFinal])}))`;
  }
  else if (campoAgente === 'status_beneficio') colSql = `bs.[description]`;
  else return ''; 

  if (Array.isArray(valorFinal)) {
    return ` AND ${colSql} IN (${toIn(valorFinal)})`;
  } else {
    if (['etapa', 'status'].includes(campoAgente)) {
         if (String(valorFinal).includes('steps.') || String(valorFinal) === 'Perícia' || String(valorFinal) === 'Exame retorno') {
             return ` AND ${colSql} = '${escapeSql(valorFinal)}'`;
         }
    }
    return ` AND ${colSql} LIKE '%${escapeSql(valorFinal)}%'`;
  }
};

const filtroFilialHibrido = (valores) => {
    if (!valores || valores.length === 0) return '';
    const likes = valores.map(v => {
        // 🚨 Remove sufixos corporativos para o LIKE funcionar perfeitamente
        let cleanVal = String(v).replace(/\b(LTDA|S\.A\.|S\/A|ME|EPP|EI)\b\.?/gi, '').trim();
        cleanVal = escapeSql(cleanVal);
        return `(c_matriz.companyName LIKE '%${cleanVal}%' OR c_filial.companyName LIKE '%${cleanVal}%')`;
    }).join(' OR ');
    return ` AND (${likes})`;
};

// =======================================================
// === 4. PREPARAÇÃO DA QUERY ===
// =======================================================
const dataInicioISO = filtros.mes_inicio ? `${filtros.mes_inicio.split('/')[1]}-${filtros.mes_inicio.split('/')[0]}-01` : '2020-01-01'; 
const dataFimISO = filtros.mes_fim ? `${filtros.mes_fim.split('/')[1]}-${filtros.mes_fim.split('/')[0]}-28` : '2026-02-28';
let intencao = (filtros.intencao || 'saude').toLowerCase(); 

// 🚨 TRAVA DE SEGURANÇA PARA A EMPRESA (ID vs Texto)
let filtroEmpresaSql = '';
if (filtros.empresa) {
    if (!isNaN(filtros.empresa)) {
        // Se for um número (ex: 1446), pesquisa pelo ID
        filtroEmpresaSql = `AND c_matriz.id = '${escapeSql(filtros.empresa)}'`;
    } else {
        // Se for texto (ex: "Supermercado Paraná LTDA"), limpa e pesquisa pelo Nome
        let cleanEmpresa = String(filtros.empresa).replace(/\b(LTDA|S\.A\.|S\/A|ME|EPP|EI)\b\.?/gi, '').trim();
        filtroEmpresaSql = `AND c_matriz.companyName LIKE '%${escapeSql(cleanEmpresa)}%'`;
    }
}
// Força o contexto se detectarmos palavras-chave
// Força o contexto se detectarmos palavras-chave
// Força o contexto se detectarmos palavras-chave
if (isAtestado) intencao = 'atestado';
else if (isBeneficio) intencao = 'beneficio'; 
else if (isAfastamento) intencao = 'saude';

// 🚨 NOVA TRAVA DE SEGURANÇA: Se o interpretador disse explicitamente "beneficio", obedeça!
if (filtros.intencao === 'beneficio') {
    intencao = 'beneficio';
}

// 🚨 TRAVA ABSOLUTA DO LIMBO: O Limbo SÓ existe no Bloco A (Saúde). 
// Se a palavra limbo estiver na lógica, ignoramos tudo e forçamos para Saúde!
if (logica.includes('limbo')) {
    intencao = 'saude';
}

const responder = (query, modo) => {
    return [{
        json: {
            query: query,
            filtrosAplicados: filtros,
            contexto: modo === "analise_atestado" ? "Gestão de Atestados" : (modo === "analise_beneficio" ? "Gestão de Benefícios" : "Gestão de Afastados"),
            modo: modo,
            isPrevisao: isPrevisao, // Flag para o próximo nó saber que é previsão
            tipo_gestor: filtros.tipo_gestor,           // 👈 ADICIONAR
            departamento_nome: filtros.departamento_nome
        }
    }];
};

// =======================================================
// === 0. INTERCEPTADOR: BUSCA DE COLABORADOR (FUZZY) ===
// =======================================================
// Se o agente sinalizar busca fuzzy, ou se a intenção for explicitamente "buscar_pessoa"
if (filtros.busca_colaborador_fuzzy === true || intencao === 'busca_colaborador') {

    // Pega o primeiro nome da lista para buscar
    let termoBusca = '';
    if (filtros.colaborador && filtros.colaborador.length > 0) {
        termoBusca = filtros.colaborador[0];
    } else if (filtros.medico && filtros.medico.length > 0) {
        termoBusca = filtros.medico[0]; // Permite buscar médico também
    }

    if (!termoBusca) {
        return responder("SELECT 'Nenhum termo de busca fornecido' as Erro", "erro");
    }

    const termoSanitizado = escapeSql(termoBusca);

    // Query para listar candidatos
    // 🚨 CORREÇÃO: Removido e.registration e usado e.id_Employee para garantir execução
    const query = `
        SELECT TOP 10 
            u.name AS Nome,
            e.id_Employee AS ID_Funcionario,
            COALESCE(c_filial.companyName, c_matriz.companyName) AS Filial,
            p.position_name AS Cargo
        FROM [user] u
        LEFT JOIN [employee] e ON u.id_user = e.user_id
        LEFT JOIN [company] c_matriz ON e.company_id = c_matriz.id
        LEFT JOIN [company] c_filial ON e.branch_id = c_filial.id
        LEFT JOIN [position] p ON e.position_id = p.id_position
        WHERE 
            u.name LIKE '%${termoSanitizado}%'
            ${filtroDepartamentoSql}
        ORDER BY u.name ASC
    `;

    return responder(query, "lista_colaboradores");
}

// =======================================================
// === BLOCO C: GESTÃO DE ATESTADOS (FLEXÍVEL) ===
// =======================================================
if (intencao === 'atestado') {

    // --- TRATAMENTO DE DATAS ---
    let dataFimSql = `EOMONTH('${dataFimISO}')`;
    try {
        if (filtros.mes_fim && filtros.mes_fim.includes('/')) {
            const [mes, ano] = filtros.mes_fim.split('/');
            const dt = new Date(parseInt(ano), parseInt(mes), 0);
            const dia = String(dt.getDate()).padStart(2, '0');
            dataFimSql = `'${ano}-${mes}-${dia}'`;
        }
    } catch(e) {}

    // 🚨 1. LÓGICA DE DATA
    let colunaData = `umi.[start_date]`; 

    let filtroPeriodo = ` AND ${colunaData} BETWEEN '${dataInicioISO}' AND ${dataFimSql} `;

    // 🚨 TRAVA DE HISTÓRICO: Se buscar pessoa específica, tira limite de data para achar atestados antigos
    if (filtros.colaborador || filtros.matricula) {
        filtroPeriodo = ``; 
    }

    // 🚨 2. JOINS
    let baseJoins = `
        FROM [user_medical_info] umi
        LEFT JOIN [medical_certificate] mc ON mc.[id_medical_certificate] = umi.[medicalCertificateIdMedicalCertificate]
        INNER JOIN [employee] e ON umi.[employeeIdEmployee] = e.[id_Employee]
        INNER JOIN [company] c_matriz ON e.[company_id] = c_matriz.[id]
        LEFT JOIN [company] c_filial ON e.[branch_id] = c_filial.[id]
        LEFT JOIN [position] p ON e.[position_id] = p.[id_position]
        LEFT JOIN [user] u ON e.[user_id] = u.[id_user]
        LEFT JOIN [user_gender] ug ON u.[gender_id] = ug.[id]
        LEFT JOIN [cost_center] cc ON e.[cost_center_id] = cc.[cost_center_id]
        LEFT JOIN [cid] c_cid ON umi.[cidIdCid] = c_cid.[id_cid]
    `;

    // --- AGRUPAMENTO INTELIGENTE ---
    let listaAgrupadores = filtros.agrupamento || [];

    if (logica.includes('medico') || logica.includes('médico') || logica.includes('doutor') || logica.includes('crm')) {
        if (!listaAgrupadores.includes('medico')) listaAgrupadores.push('medico');
    }

    if (logica.includes('dia da semana') || logica.includes('dias da semana') || logica.includes('semanal')) {
         const hasDay = listaAgrupadores.some(a => a.toLowerCase().includes('dia') || a.toLowerCase().includes('semana'));
         if (!hasDay) listaAgrupadores.push('Dia_da_Semana');
    }

    if (filtros.metrica === 'ranking' && filtros.ranking_tipo && listaAgrupadores.length === 0) {
        listaAgrupadores.push(filtros.ranking_tipo);
    }

    const temAgrupamentoEspecifico = listaAgrupadores.some(a => ['medico', 'dia_da_semana', 'dia'].includes(a.toLowerCase()));

    if (filtros.mes_inicio && filtros.mes_fim && filtros.mes_inicio !== filtros.mes_fim && !temAgrupamentoEspecifico) {
        if (listaAgrupadores.length === 0 && filtros.metrica !== 'total') { 
            listaAgrupadores.unshift('mes'); 
        }
    }

    // --- 3. LÓGICA DE STATUS DINÂMICA (A Mágica acontece aqui) ---
    // Padrão: Aprovados (2). Se a NLP detectar outra intenção, muda.
    let filtroStatus = ` AND umi.[statusMedicalIdStatusMedical] = 2 `; 
    let usuarioDefiniuStatus = false; // Flag para saber se o usuário escolheu

    const isAnaliseStatus = listaAgrupadores.includes('status');
    // 🚨 MELHORIA: Usa a estrutura do JSON em vez de procurar palavras soltas
    const isBuscaDetalhada = 
        filtros.metrica === 'total' ||           // Se pediu TOTAL, quer ver tudo
        filtros.tipo_calculo === 'quantidade' || // Se pediu QUANTIDADE, quer ver o volume recebido
        filtros.matricula || 
        filtros.colaborador ||
        // Mantém verificação de palavras apenas como fallback
        logica.includes('recebemos') || logica.includes('recebido') || logica.includes('quantidade') || logica.includes('enviou') || logica.includes('entregou') || logica.includes('total');

    if (isAnaliseStatus || isBuscaDetalhada) {
        filtroStatus = ` AND umi.[statusMedicalIdStatusMedical] IN (1, 2, 3) `;
        usuarioDefiniuStatus = true;
    }

    if (logica.includes('pendente') || logica.includes('em analise') || logica.includes('aguardando')) {
        filtroStatus = ` AND umi.[statusMedicalIdStatusMedical] = 1 `;
        usuarioDefiniuStatus = true;
    }
    if (logica.includes('rejeitado') || logica.includes('indeferido')) {
        filtroStatus = ` AND umi.[statusMedicalIdStatusMedical] = 3 `;
        usuarioDefiniuStatus = true;
    }
    if (logica.includes('todos') || logica.includes('geral')) {
        filtroStatus = ` AND umi.[statusMedicalIdStatusMedical] IN (1, 2, 3) `;
        usuarioDefiniuStatus = true;
    }

    // --- VÍNCULO ---
    let filtroVinculo = '';
    // Adicionamos 'cid' na verificação. Se pedir CID + Afastamento, filtra.
    const isVinculado = (logica.includes('afastamento') || logica.includes('vinculad') || logica.includes('previdencia')); 

    let temFiltroStatusAfastado = (filtros.status && filtros.status.toLowerCase().includes('afastad'));
    if (filtros.tipo_calculo === 'dias_ausencia') temFiltroStatusAfastado = false; 

    if ((isVinculado || temFiltroStatusAfastado) && !isAnaliseStatus) {
        // Esse filtro garante que só pegamos os atestados que estão na tabela register_absence
        filtroVinculo = ` 
            AND EXISTS (
                SELECT 1 FROM [register_absence] ra 
                WHERE ra.user_medical_info_id = umi.id_user_medical_info
            ) 
        `;
    }

    // 🚨 4. WHERE BASE
    const whereClauseBase = `
        WHERE 1=1
        ${filtroPeriodo}
        AND umi.delete_datetime IS NULL 
        ${filtroStatus}
        ${filtroVinculo} 
        ${filtroEmpresaSql}
        ${filtroDepartamentoSql}
        ${filtros.filial ? filtroFilialHibrido(filtros.filial) : ''}
        ${filtros.cargo ? filtroTxt('p', 'cargo', filtros.cargo) : ''}
        ${filtros.sexo ? filtroTxt('ug', 'sexo', filtros.sexo) : ''}
        ${filtros.centro_de_custo ? filtroTxt('cc', 'centro_de_custo', filtros.centro_de_custo) : ''}
        ${filtros.medico ? filtroTxt('umi', 'medico', filtros.medico) : ''}
        ${filtros.cid_grupo ? filtroTxt('c_cid', 'cid_grupo', filtros.cid_grupo) : ''}
        ${filtros.colaborador ? filtroTxt('u', 'colaborador', filtros.colaborador) : ''}
        ${filtros.matricula ? `AND e.id_Employee = '${escapeSql(filtros.matricula)}'` : ''}
    `;

    let selectCols = [];
    let groupCols = [];
    let orderBy = ``;
    let metricasSql = ``;

    // =======================================================
    // 🧠 5. DEFINIÇÃO DAS MÉTRICAS
    // =======================================================
    const tipoCalculo = filtros.tipo_calculo || 'quantidade';

    // A) CUSTO
    if (tipoCalculo === 'custo' || (logica.includes('custo') && logica.includes('cid'))) {
        metricasSql = `
            SUM(
                ISNULL(
                    ((CAST(e.salary AS NUMERIC(18,2))/100) / 30.0) *
                    CASE 
                        WHEN umi.is_hours_certificates = 1 THEN COALESCE(umi.consecutive_hours, 0) / 1440.0
                        ELSE COALESCE(umi.consecutive_days, 0)
                    END,
                    0
                )
            ) as Custo_Total
        `;
        if (filtros.ranking_tipo === 'cid' || logica.includes('cid')) {
             if (!groupCols.some(g => g.includes('code_cid'))) {
                const cidGroupSql = `LEFT(c_cid.code_cid, 1)`;
                selectCols.push(`${cidGroupSql} as Letra_CID`);
                groupCols.push(cidGroupSql);
            }
        }
        orderBy = `Custo_Total DESC`;

        // SÓ FORÇA APROVADO SE O USUÁRIO NÃO PEDIU OUTRA COISA
        if (!usuarioDefiniuStatus) {
            filtroStatus = ` AND umi.[statusMedicalIdStatusMedical] = 2 `; 
        }
    }

    // B) DIAS DE AUSÊNCIA
    else if (tipoCalculo === 'dias_ausencia' || logica.includes('dias de ausencia') || logica.includes('dias perdidos')) {
        metricasSql = `
            SUM(
                CASE
                    WHEN umi.is_hours_certificates = 1 THEN
                        umi.consecutive_hours / 1440.0
                    ELSE
                        CAST(DATEDIFF(DAY, umi.start_date, COALESCE(umi.end_date, CAST(GETDATE() AS DATE))) AS BIGINT) + 1
                END
            ) as Total_Dias_Ausencia
        `;
        orderBy = `Total_Dias_Ausencia DESC`;

        // SÓ FORÇA APROVADO SE O USUÁRIO NÃO PEDIU OUTRA COISA
        if (!usuarioDefiniuStatus) {
            filtroStatus = ` AND umi.[statusMedicalIdStatusMedical] = 2 `; 
        }

        if (listaAgrupadores.includes('mes')) {
             selectCols.push(`FORMAT(umi.[start_date], 'MM/yyyy') as Mes`);
             groupCols.push(`FORMAT(umi.[start_date], 'MM/yyyy')`);
             orderBy = `MIN(umi.[start_date]) ASC`;
        }
    }

    // C) TEMPO MÉDIO
    else if (tipoCalculo === 'tempo_medio' || logica.includes('tempo medio')) {
        metricasSql = `
            AVG(
              CAST(
                CASE 
                  WHEN umi.is_hours_certificates = 1 THEN COALESCE(umi.consecutive_hours, 0) / 1440.0
                  ELSE COALESCE(umi.consecutive_days, DATEDIFF(DAY, umi.start_date, COALESCE(umi.end_date, GETDATE())) + 1)
                END AS FLOAT
              )
            ) as Media_Dias
        `;
        // SÓ FORÇA APROVADO SE O USUÁRIO NÃO PEDIU OUTRA COISA
        if (!usuarioDefiniuStatus) {
            filtroStatus = ` AND umi.[statusMedicalIdStatusMedical] = 2 `; 
        }
    }

    // D) PORCENTAGEM
    else if (tipoCalculo === 'porcentagem' || logica.includes('porcentagem')) {
        const isHoras = logica.includes('hora'); 
        const condicaoAlvo = isHoras 
            ? "umi.is_hours_certificates = 1" 
            : "(umi.is_hours_certificates = 0 OR umi.is_hours_certificates IS NULL)";

        const nomeQtd = isHoras ? 'Qtd_em_Horas' : 'Qtd_em_Dias';

        metricasSql = `
            COUNT(CASE WHEN ${condicaoAlvo} THEN 1 END) as ${nomeQtd},
            COUNT(*) as Total_Geral,
            (CAST(COUNT(CASE WHEN ${condicaoAlvo} THEN 1 END) AS FLOAT) / NULLIF(CAST(COUNT(*) AS FLOAT),0)) * 100 as Porcentagem
        `;

        // Se o usuário não definiu, porcentagem costuma olhar tudo (limpa o filtro)
        if (!usuarioDefiniuStatus) {
            filtroStatus = ``; 
        }
        orderBy = `Porcentagem DESC`;
    }
     // 🚨 F) POR COLABORADOR (TABELA SUGESTIVO CRÔNICO - CORRIGIDA)
    // Baseado em: signChronicallyAbsentRepository
    // Filtro essencial: INNER JOIN com register_absence para garantir que é um afastamento relevante
    // 🚨 F) POR COLABORADOR
    else if (listaAgrupadores.includes('colaborador') || listaAgrupadores.includes('usuario')) {

        // 1. Filtros de Vínculo
        const pediuVinculado = logica.includes('vinculado') || logica.includes('afastamento') || logica.includes('cronico');
        const pediuNaoVinculado = logica.includes('nao vinculado') || logica.includes('não vinculado') || logica.includes('apenas atestado');

        let filtroVinculoLocal = '';
        if (pediuVinculado) {
             filtroVinculoLocal = ` AND EXISTS (SELECT 1 FROM [register_absence] ra WHERE ra.user_medical_info_id = umi.id_user_medical_info) `;
        } else if (pediuNaoVinculado) {
             filtroVinculoLocal = ` AND NOT EXISTS (SELECT 1 FROM [register_absence] ra WHERE ra.user_medical_info_id = umi.id_user_medical_info) `;
        }

        // 🚨 NOVO BIFURCADOR: Se pediu CID, mostra a CID. Se não, mostra o Custo (Crônico)
        if (listaAgrupadores.includes('cid') || listaAgrupadores.includes('cid_grupo')) {
            // A métrica vira apenas datas e o agrupador (tratado mais abaixo) puxará a CID.
            metricasSql = `
                FORMAT(MAX(umi.start_date), 'dd/MM/yyyy') as Data_Ultimo_Atestado,
                COUNT(umi.id_user_medical_info) as Ocorrencias
            `;
            orderBy = `Data_Ultimo_Atestado DESC`;
        } 
        else {
            // Lógica Original de Sugestivo Crônico (Custo Total)
            const queryClean = `
                SELECT TOP 100 
                    u.name as Colaborador, 
                    COUNT(DISTINCT umi.id_user_medical_info) as Qtd_Atestados,

                    -- Soma de Dias
                    SUM(
                        CASE 
                            WHEN umi.consecutive_days IS NOT NULL AND umi.consecutive_days > 0 THEN umi.consecutive_days
                            WHEN umi.end_date IS NOT NULL THEN DATEDIFF(DAY, umi.start_date, umi.end_date)
                            ELSE DATEDIFF(DAY, umi.start_date, GETDATE())
                        END
                    ) as Total_Dias,

                    -- Soma de Custo (Salário / 100 / 30 * Dias)
                    SUM(
                        ((COALESCE(TRY_CONVERT(FLOAT, e.salary), 0) / 100.0) / 30.0) *
                        (
                            CASE 
                                WHEN umi.consecutive_days IS NOT NULL AND umi.consecutive_days > 0 THEN umi.consecutive_days
                                WHEN umi.end_date IS NOT NULL THEN DATEDIFF(DAY, umi.start_date, umi.end_date)
                                ELSE DATEDIFF(DAY, umi.start_date, GETDATE())
                            END
                        )
                    ) as Custo_Total

                FROM [user_medical_info] umi
                INNER JOIN [employee] e ON umi.[employeeIdEmployee] = e.[id_Employee]
                INNER JOIN [user] u ON e.[user_id] = u.[id_user]
                INNER JOIN [company] c_matriz ON e.[company_id] = c_matriz.[id]
                LEFT JOIN [company] c_filial ON e.[branch_id] = c_filial.[id]

                WHERE 1=1 
                ${filtroPeriodo}
                AND umi.[delete] = 'N'
                -- 🚨 NOVO: Usa o filtroStatus numérico (1, 2 ou 3) que já foi calculado no início do bloco
                ${usuarioDefiniuStatus ? filtroStatus : 'AND umi.[statusMedicalIdStatusMedical] = 2'}
                ${filtroVinculoLocal}
                ${filtroEmpresaSql}
                ${filtros.filial ? filtroFilialHibrido(filtros.filial) : ''}
                ${filtros.matricula ? `AND e.id_Employee = '${escapeSql(filtros.matricula)}'` : ''}

                GROUP BY u.name
                HAVING SUM(
                    CASE 
                        WHEN umi.consecutive_days IS NOT NULL AND umi.consecutive_days > 0 THEN umi.consecutive_days
                        WHEN umi.end_date IS NOT NULL THEN DATEDIFF(DAY, umi.start_date, umi.end_date)
                        ELSE DATEDIFF(DAY, umi.start_date, GETDATE())
                    END
                ) > 0 

                ORDER BY Custo_Total DESC
            `;

            return responder(queryClean, "analise_atestado");
        }
    }

    // F) QUANTIDADE (PADRÃO)
    else {
        // Define o nome da coluna principal
        let labelTotal = (filtroVinculo && filtroVinculo.trim() !== '') 
            ? 'Qtd_Atestados_Vinculados' 
            : 'Total_Enviados';

        const temFiltroVinculo = (filtroVinculo && filtroVinculo.trim() !== '');

      // 🚨 DETECTA SE PEDIU STATUS ESPECÍFICO
        const isFiltroAprovado = logica.includes('aprovado') || (filtros.status === 'Aprovado');
        const isFiltroPendente = logica.includes('pendente') || logica.includes('em analise') || (filtros.status === 'Pendente');
        const isFiltroRecusado = logica.includes('recusado') || logica.includes('rejeitado') || logica.includes('indeferido') || (filtros.status === 'Recusado') || (filtros.status === 'reprovado') || (filtros.status === 'Reprovado');

        const temFiltroStatusEspecifico = isFiltroAprovado || isFiltroPendente || isFiltroRecusado;
        // 🚨 REGRA DE EXIBIÇÃO:
        // Só mostramos o breakdown completo (4 colunas) se for uma pergunta GERAL ("Quantos recebemos?").
        // Se for específica ("Quantos recusados?" ou "Quantos com vínculo?"), mostramos só o número alvo.
        const mostrarDetalhes = isBuscaDetalhada && !temFiltroStatusEspecifico && !temFiltroVinculo;

        if (mostrarDetalhes) {
            metricasSql = `
                COUNT(DISTINCT umi.id_user_medical_info) as ${labelTotal},
                COUNT(DISTINCT CASE WHEN umi.statusMedicalIdStatusMedical = 2 THEN umi.id_user_medical_info END) as Qtd_Aprovados,
                COUNT(DISTINCT CASE WHEN umi.statusMedicalIdStatusMedical = 1 THEN umi.id_user_medical_info END) as Qtd_Pendentes,
                COUNT(DISTINCT CASE WHEN umi.statusMedicalIdStatusMedical = 3 THEN umi.id_user_medical_info END) as Qtd_Rejeitados
            `;
            orderBy = `${labelTotal} DESC`;
        } else {
            // Visão Focada (1 Coluna)

            // Renomeia a coluna para combinar com a pergunta
            if (isFiltroAprovado) labelTotal = 'Qtd_Aprovados';
            else if (isFiltroPendente) labelTotal = 'Qtd_Pendentes';
            else if (isFiltroRecusado) labelTotal = 'Qtd_Rejeitados';

            metricasSql = `COUNT(DISTINCT umi.id_user_medical_info) as ${labelTotal}`;
            orderBy = `${labelTotal} DESC`;
        }
    }


    // --- APLICAR AGRUPADORES GENÉRICOS (Se não foram tratados acima) ---
    if (!groupCols.length) {
        listaAgrupadores.forEach(a => {
            const campo = a.toLowerCase();
            if (campo === 'status') {
                selectCols.push(`CASE umi.[statusMedicalIdStatusMedical] WHEN 1 THEN 'Aguardando' WHEN 2 THEN 'Aprovado' WHEN 3 THEN 'Recusado' ELSE 'Outro' END as Status_Atestado`);
                groupCols.push(`umi.[statusMedicalIdStatusMedical]`);
                orderBy = `umi.[statusMedicalIdStatusMedical] ASC`;
            } else if (campo === 'mes') {
                selectCols.push(`FORMAT(umi.[start_date], 'MM/yyyy') as Mes`);
                groupCols.push(`FORMAT(umi.[start_date], 'MM/yyyy')`);
                if(!orderBy || !orderBy.includes('DESC')) orderBy = `MIN(umi.[start_date]) ASC`;
            } else if (campo === 'medico') {
                selectCols.push(`umi.[doctor_name] as Medico`);
                groupCols.push(`umi.[doctor_name]`);
            } else if (campo.includes('dia')) { 
                const diaSemanaSql = `DATENAME(weekday, umi.[start_date])`;
                selectCols.push(`${diaSemanaSql} as Dia_Semana`);
                groupCols.push(`DATEPART(weekday, umi.[start_date])`, `DATENAME(weekday, umi.[start_date])`); 
                if(!orderBy || !orderBy.includes('Total')) orderBy = `DATEPART(weekday, MIN(umi.[start_date])) ASC`; 
            } // 🚨 CID EXATA vs GRUPO DE CID
        else if (campo === 'cid') {
            selectCols.push(`CONCAT(c_cid.code_cid, ' - ', c_cid.[description]) as CID_Exato`);
            groupCols.push(`c_cid.code_cid`, `c_cid.[description]`);
        } 
        else if (campo === 'cid_grupo') {
            const cidGroupSql = `CASE WHEN c_cid.code_cid LIKE 'A%' OR c_cid.code_cid LIKE 'B%' THEN 'A00-B99 - Algumas doenças infecciosas e parasitárias' WHEN c_cid.code_cid LIKE 'C%' OR c_cid.code_cid LIKE 'D0%' OR c_cid.code_cid LIKE 'D1%' OR c_cid.code_cid LIKE 'D2%' OR c_cid.code_cid LIKE 'D3%' OR c_cid.code_cid LIKE 'D4%' THEN 'C00-D48 - Neoplasias (tumores)' WHEN c_cid.code_cid LIKE 'D5%' OR c_cid.code_cid LIKE 'D6%' OR c_cid.code_cid LIKE 'D7%' OR c_cid.code_cid LIKE 'D8%' THEN 'D50-D89 - Doenças do sangue e dos órgãos hematopoéticos' WHEN c_cid.code_cid LIKE 'E%' THEN 'E00-E90 - Doenças endócrinas, nutricionais e metabólicas' WHEN c_cid.code_cid LIKE 'F%' THEN 'F00-F99 - Transtornos mentais e comportamentais' WHEN c_cid.code_cid LIKE 'M%' THEN 'M00-M99 - Doenças do sistema osteomuscular e do tecido conjuntivo' WHEN c_cid.code_cid LIKE 'Z%' THEN 'Z00-Z99 - Fatores que influenciam o estado de saúde' ELSE 'Outros / Não Identificado' END`;
            selectCols.push(`${cidGroupSql} as Grupo_CID`); groupCols.push(cidGroupSql);
        } else if (campo === 'filial') {
                const col = `COALESCE(c_filial.companyName, c_matriz.companyName)`;
                selectCols.push(`${col} as Filial`); groupCols.push(col);
            } else if (campo === 'empresa') { 
                selectCols.push(`c_matriz.companyName as Empresa`); 
                groupCols.push(`c_matriz.companyName`); 
            } else if (campo === 'sexo') { 
                selectCols.push(`ug.[label] as Sexo`); 
                groupCols.push(`ug.[label]`); 
            }
            else if (campo === 'cargo') { 
                selectCols.push(`p.[position_name] as Cargo`); 
                groupCols.push(`p.[position_name]`); 
            } else if (campo === 'faixa_etaria') {
                const faixaSql = `
                    CASE 
                        WHEN DATEDIFF(YEAR, u.birthdate, GETDATE()) < 20 THEN '< 20 anos'
                        WHEN DATEDIFF(YEAR, u.birthdate, GETDATE()) BETWEEN 20 AND 29 THEN '20-29 anos'
                        WHEN DATEDIFF(YEAR, u.birthdate, GETDATE()) BETWEEN 30 AND 39 THEN '30-39 anos'
                        WHEN DATEDIFF(YEAR, u.birthdate, GETDATE()) BETWEEN 40 AND 49 THEN '40-49 anos'
                        WHEN DATEDIFF(YEAR, u.birthdate, GETDATE()) BETWEEN 50 AND 59 THEN '50-59 anos'
                        ELSE '60+ anos'
                    END
                `;
                selectCols.push(`${faixaSql} as Faixa_Etaria`);
                groupCols.push(faixaSql);
            } // 🚨 ADICIONE ISTO DENTRO DO LOOP DO BLOCO A
            else if (campo === 'centro_de_custo' || campo === 'centro de custo') {
                selectCols.push(`cc.[name] as Centro_de_Custo`); 
                groupCols.push(`cc.[name]`);
            }
        });
    }

    // 🚨 ORDEM CRÍTICA: Definir colunasSelect ANTES de usar na query
    const colunasSelect = selectCols.length > 0 ? selectCols.join(', ') + ',' : '';
    const colunasGroup = groupCols.length > 0 ? 'GROUP BY ' + groupCols.join(', ') : '';

    // 🚨 RE-APLICAÇÃO DO FILTRO DE STATUS NO FINAL
    const whereFinal = `${whereClauseBase} ${filtroStatus} ${filtroVinculo || ''}`;

    const query = `SELECT TOP 100 ${colunasSelect} ${metricasSql} ${baseJoins} ${whereFinal} ${colunasGroup} ${orderBy ? 'ORDER BY ' + orderBy : ''}`;

    return responder(query, "analise_atestado");
}

// =======================================================
// === BLOCO A: GESTÃO DE AFASTADOS (SAÚDE - FINAL) ===
// =======================================================
if (intencao === 'saude') {

    // 1. INICIALIZAR VARIÁVEIS NO TOPO (Escopo Global do Bloco)
    let agrupadores = filtros.agrupamento || [];
    let filtroExameObrigatorio = '';
    let colunaCount = 'us.id_user_steps'; 
    let nomeColuna = 'Qtd_Afastamentos';

  // 🚨 AJUSTE DE CONTAGEM: PESSOAS VS EVENTOS
    // Se a lógica da pergunta menciona "colaborador", "funcionário" ou "pessoa", 
    // mudamos a contagem para o ID do Funcionário, eliminando as duplicidades.
    if (logica.includes('colaborador') || logica.includes('funcionario') || logica.includes('pessoa')) {
        colunaCount = 'e.id_Employee';
        nomeColuna = 'Qtd_Colaboradores_Afastados';
    }

    // Força agrupamento
    if (logica.includes('empresa') && !agrupadores.includes('empresa')) agrupadores.push('empresa');
    if (logica.includes('filial') && !agrupadores.includes('filial')) agrupadores.push('filial');

    // 2. DEFINIR FILTRO DE ACIDENTE (PARA USAR EM TODAS AS QUERIES)
    let filtroTipoAfastamento = '';

    if (filtros.tipo_afastamento === 'Acidente' || logica.includes('acidente')) {
        filtroTipoAfastamento = ` AND (war.id_work_accident_reporting IS NOT NULL OR bt.benefit_type_code IN ('91', '92', '93', '94')) `;
        nomeColuna = 'Qtd_Acidentes';
    } 
    else if (filtros.tipo_afastamento === 'Doença') {
        filtroTipoAfastamento = ` AND (war.id_work_accident_reporting IS NULL AND (bt.benefit_type_code NOT IN ('91', '92', '93', '94') OR bt.benefit_type_code IS NULL)) `;
    }

    // 3. DETECÇÃO DE MODO TEMPORAL
    // 3. DETECÇÃO DE MODO TEMPORAL
    const isAnaliseTemporal = 
        filtros.metrica === 'evolucao' || 
        filtros.metrica === 'previsao' || 
        isPrevisao === true || 
        logica.includes('mes a mes') || 
        logica.includes('evolucao') || 
        logica.includes('historico') ||
        logica.includes('tendencia');

    // 🚨 TRAVA DE SEGURANÇA: Se o usuário pedir lista de pessoas ou limbo, cancela a evolução temporal!
    const cancelarEvolucao = agrupadores.includes('colaborador') || logica.includes('limbo');

    // --- SUB-BLOCO: EVOLUÇÃO ---
    if (isAnaliseTemporal && !cancelarEvolucao && !logica.includes('apenas novos') && !logica.includes('somente novos')) {
        const filtrosComuns = `
            ${filtroEmpresaSql}
            ${filtros.filial ? filtroFilialHibrido(filtros.filial) : ''}
            ${filtros.cargo ? filtroTxt('p', 'cargo', filtros.cargo) : ''}
            ${filtros.sexo ? filtroTxt('ug', 'sexo', filtros.sexo) : ''}
            ${filtros.centro_de_custo ? filtroTxt('cc', 'centro_de_custo', filtros.centro_de_custo) : ''}
            ${filtroTipoAfastamento} 
        `;

        const queryEvolucao = `
            WITH Movimentacao AS (
                SELECT FORMAT(us.date_absence, 'yyyy-MM') as Mes_Ord, FORMAT(us.date_absence, 'MM/yyyy') as Mes_Formatado, 1 as Qtd_Movimento
                FROM [user_steps] us
                INNER JOIN [employee] e ON us.employeeIdEmployee = e.id_Employee
                INNER JOIN [company] c ON e.company_id = c.id
                LEFT JOIN [position] p ON e.position_id = p.id_position
                LEFT JOIN [user] u ON e.user_id = u.id_user
                LEFT JOIN [user_gender] ug ON u.gender_id = ug.id
                LEFT JOIN [cost_center] cc ON e.cost_center_id = cc.cost_center_id
                -- Joins para Filtro de Acidente
                LEFT JOIN [user_benefit] ub ON us.[id_user_steps] = ub.[userStepsIdUserSteps]
                LEFT JOIN [benefit_type] bt ON ub.[benefitTypeIdBenefitType] = bt.[id_benefit_type]
                LEFT JOIN [work_accident_reporting] war ON us.[workAccidentIdWorkAccidentReporting] = war.[id_work_accident_reporting]

                WHERE us.[delete] = 'N' AND us.date_absence BETWEEN '${dataInicioISO}' AND EOMONTH('${dataFimISO}')
                ${filtrosComuns}

                UNION ALL

                SELECT FORMAT(ur.execution_date, 'yyyy-MM') as Mes_Ord, FORMAT(ur.execution_date, 'MM/yyyy') as Mes_Formatado, -1 as Qtd_Movimento
                FROM [user_return] ur
                INNER JOIN [user_steps] us ON ur.userStepsIdUserSteps = us.id_user_steps
                INNER JOIN [employee] e ON us.employeeIdEmployee = e.id_Employee
                INNER JOIN [company] c ON e.company_id = c.id
                LEFT JOIN [position] p ON e.position_id = p.id_position
                LEFT JOIN [user] u ON e.user_id = u.id_user
                LEFT JOIN [user_gender] ug ON u.gender_id = ug.id
                LEFT JOIN [cost_center] cc ON e.cost_center_id = cc.cost_center_id
                -- Joins para Filtro de Acidente
                LEFT JOIN [user_benefit] ub ON us.[id_user_steps] = ub.[userStepsIdUserSteps]
                LEFT JOIN [benefit_type] bt ON ub.[benefitTypeIdBenefitType] = bt.[id_benefit_type]
                LEFT JOIN [work_accident_reporting] war ON us.[workAccidentIdWorkAccidentReporting] = war.[id_work_accident_reporting]

                WHERE ur.delete_datetime IS NULL AND ur.return_status_id = 1 
                AND ur.execution_date BETWEEN '${dataInicioISO}' AND EOMONTH('${dataFimISO}')
                ${filtrosComuns}
            )
            SELECT 
                Mes_Formatado as Mes,
                SUM(CASE WHEN Qtd_Movimento > 0 THEN 1 ELSE 0 END) as Qtd_Novos_Afastamentos,
                SUM(CASE WHEN Qtd_Movimento < 0 THEN 1 ELSE 0 END) as Qtd_Retornos,
                SUM(Qtd_Movimento) as Variacao_Liquida,
                SUM(SUM(Qtd_Movimento)) OVER (ORDER BY Mes_Ord ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as Total_Ativos_Acumulado
            FROM Movimentacao
            GROUP BY Mes_Ord, Mes_Formatado
            ORDER BY Mes_Ord
        `;
        return responder(queryEvolucao, "analise_saude_evolucao");
    }

    // =======================================================
    // === LÓGICA PADRÃO (CONTAGEM SIMPLES / LISTAGEM) ===
    // =======================================================

    // Se o status for "Afastado" ou tiver palavras de estoque, mudamos a lógica temporal
    // 🚨 AJUSTE CRÍTICO: Limbo e Afastados são sempre ESTOQUE (olham para o passado até a data atual)
    const isEstoque = 
        logica.includes('hoje') || 
        logica.includes('agora') || 
        logica.includes('momento') || 
        logica.includes('atualmente') ||
        logica.includes('limbo') || 
        (filtros.status && filtros.status.toLowerCase().includes('afastad'));

    if (isEstoque) {
        // Lógica Inteligente:
        // 1. Se for pergunta de "HOJE", a referência é o dia atual (GETDATE).
        // 2. Se for histórico ("Quantos ativos em Dezembro?"), a referência é o fim daquele mês.

        const dataReferencia = (logica.includes('hoje') || logica.includes('agora') || logica.includes('atualmente')) 
            ? `CAST(GETDATE() AS DATE)` 
            : `EOMONTH('${dataFimISO}')`;

        // Regra:
        // - O afastamento começou ANTES ou NA data de referência.
        // - E a pessoa NÃO VOLTOU (NULL) ...
        // - ... OU a volta está agendada para DEPOIS da data de referência (Futuro).
        // Quem já voltou (data retorno <= referencia) é excluído.
        filtroPeriodo = ` 
            AND us.[date_absence] <= ${dataReferencia} 
            AND (ur.execution_date IS NULL OR ur.execution_date > ${dataReferencia})
        `;
    } else {
        // Lógica Padrão (Fluxo): O afastamento começou DENTRO do mês (Novos Casos)
        filtroPeriodo = ` AND us.[date_absence] BETWEEN '${dataInicioISO}' AND EOMONTH('${dataFimISO}') `;
    }

    let baseJoins = `
        FROM [user_steps] us
        INNER JOIN [employee] e ON us.[employeeIdEmployee] = e.[id_Employee]
        INNER JOIN [company] c_matriz ON e.[company_id] = c_matriz.[id]
        LEFT JOIN [company] c_filial ON e.[branch_id] = c_filial.[id]
        LEFT JOIN [position] p ON e.[position_id] = p.[id_position]
        LEFT JOIN [steps] s ON us.[stepsIdSteps] = s.[id_steps]
        LEFT JOIN [ga_situation] gs ON us.[gaSituationIdGaSituation] = gs.[id_ga_situation]
        LEFT JOIN [cid] c_cid ON us.[cidIdCid] = c_cid.[id_cid] 
        LEFT JOIN [user] u ON e.[user_id] = u.[id_user]
        LEFT JOIN [user_gender] ug ON u.[gender_id] = ug.[id]
        LEFT JOIN [cost_center] cc ON e.[cost_center_id] = cc.[cost_center_id]
        LEFT JOIN [user_benefit] ub ON us.[id_user_steps] = ub.[userStepsIdUserSteps]
        LEFT JOIN [benefit_type] bt ON ub.[benefitTypeIdBenefitType] = bt.[id_benefit_type]
        LEFT JOIN [work_accident_reporting] war ON us.[workAccidentIdWorkAccidentReporting] = war.[id_work_accident_reporting]
        LEFT JOIN [user_return] ur ON ur.[userStepsIdUserSteps] = us.[id_user_steps] AND ur.return_status_id = 1
    `;

    // 🚨 REMOVIDO 'let' DAQUI POIS JÁ FOI DECLARADO NO TOPO
    // Apenas atribuímos valores se necessário
    colunaCount = 'us.id_user_steps'; 

    if (isBuscaExame) {
        baseJoins += ` LEFT JOIN [user_medical_examination] ume ON us.[id_user_steps] = ume.[userStepsIdUserSteps] `; 
        filtroExameObrigatorio = ` AND ume.id_user_medical_examination IS NOT NULL `;
        colunaCount = 'ume.id_user_medical_examination';
        nomeColuna = 'Qtd_Exames';
    } else {
        if (filtros.ranking_tipo === 'cid' || agrupadores.includes('cid')) {
            nomeColuna = 'Qtd_Casos';
        }
    }

    let filtroStatusLimbo = '';
    if (logica.includes('limbo')) {
        filtroStatusLimbo = ` AND us.gaSituationIdGaSituation = 5 `;
        filtros.status = null;
        filtroExameObrigatorio = ''; 
        colunaCount = 'us.id_user_steps';
        nomeColuna = 'Qtd_Casos_Limbo';
    }

    if ((logica.includes('pericia') || logica.includes('agendamento')) && (logica.includes('agendada') || logica.includes('marcada') || logica.includes('prevista') || filtros.status === 'Agendado')) {
        filtroStatusLimbo = ` AND us.gaSituationIdGaSituation = 2 `; 
        filtros.status = null; filtros.etapa = null; filtroExameObrigatorio = ''; colunaCount = 'us.id_user_steps'; nomeColuna = 'Qtd_Pericias_Agendadas';
    }
    if (logica.includes('alta') && (logica.includes('antecipada') || logica.includes('medica'))) {
        filtroStatusLimbo = ` AND us.medical_release IN (1, 2) `; filtros.status = null; filtroPeriodo = ''; nomeColuna = 'Qtd_Altas_Antecipadas';
    }

    const whereClause = `
        WHERE 1=1
        ${filtroPeriodo}
        AND us.[delete] = 'N' 
        ${filtroStatusLimbo}
        ${filtroTipoAfastamento} 
        ${filtroEmpresaSql}
        ${filtroDepartamentoSql}
