            FORMAT(MAX(ub.[end_date]), 'dd/MM/yyyy') as Fim_Beneficio
        `;
        orderBy = `u.[name] ASC`; 
    }
    else {
        // Se não for lista, mantém a contagem ou média padrão
        const isPedidoTempo = filtros.tipo_calculo === 'tempo_medio' || 
            ((logica.includes('tempo') || logica.includes('duracao') || logica.includes('media')) && filtros.tipo_calculo !== 'quantidade');

        if (isPedidoTempo) {
            const formulaMedia = `CAST(AVG(DATEDIFF(day, us.date_absence, GETDATE())) / 30.44 AS DECIMAL(10,2))`;
            metricasSql = `${formulaMedia} AS Media_Meses_Afastamento`;
            orderBy = `${formulaMedia} DESC`; 
        } else {
            metricasSql = `COUNT(DISTINCT ${colunaCount}) as ${nomeColuna}`;
        }
    }

    agrupadores.forEach(a => {
        const campo = a.toLowerCase();
        if (campo === 'filial') { selectCols.push(`COALESCE(c_filial.companyName, c_matriz.companyName) as Filial`); groupCols.push(`COALESCE(c_filial.companyName, c_matriz.companyName)`); }
        else if (campo === 'empresa') { selectCols.push(`c_matriz.[companyName] as Empresa`); groupCols.push(`c_matriz.[companyName]`); }
        else if (campo === 'mes') { hasMonthGroup = true; selectCols.push(`FORMAT(us.date_absence, 'MM/yyyy') as Mes`); groupCols.push(`FORMAT(us.date_absence, 'MM/yyyy')`); orderBy = `MIN(us.date_absence) ASC`; }
        else if (campo === 'sexo') { selectCols.push(`ug.[label] as Sexo`); groupCols.push(`ug.[label]`); }
        else if (campo === 'status') { selectCols.push(`gs.[description] as Status`); groupCols.push(`gs.[description]`); }
        else if (campo === 'cargo') { selectCols.push(`p.[position_name] as Cargo`); groupCols.push(`p.[position_name]`); }
          // 🚨 ALTERAÇÃO AQUI: Adiciona Nome e CPF para garantir unicidade na lista
        else if (campo === 'colaborador' || campo === 'usuario') { 
            selectCols.push(`u.[name] as Colaborador`, `u.[cpf] as CPF`); 
            groupCols.push(`u.[name]`, `u.[cpf]`); 
        }
        else if (campo === 'centro_de_custo') { selectCols.push(`cc.[name] as Centro_de_Custo`); groupCols.push(`cc.[name]`); }
        else if (campo === 'faixa_etaria') {
            const faixaSql = `CASE WHEN DATEDIFF(YEAR, u.birthdate, GETDATE()) < 20 THEN '< 20 anos' WHEN DATEDIFF(YEAR, u.birthdate, GETDATE()) BETWEEN 20 AND 29 THEN '20-29 anos' WHEN DATEDIFF(YEAR, u.birthdate, GETDATE()) BETWEEN 30 AND 39 THEN '30-39 anos' WHEN DATEDIFF(YEAR, u.birthdate, GETDATE()) BETWEEN 40 AND 49 THEN '40-49 anos' WHEN DATEDIFF(YEAR, u.birthdate, GETDATE()) BETWEEN 50 AND 59 THEN '50-59 anos' ELSE '60+ anos' END`;
            selectCols.push(`${faixaSql} as Faixa_Etaria`); groupCols.push(faixaSql);
        }
        // 🚨 CID EXATA vs GRUPO DE CID
        else if (campo === 'cid') {
            selectCols.push(`CONCAT(c_cid.code_cid, ' - ', c_cid.[description]) as CID_Exato`);
            groupCols.push(`c_cid.code_cid`, `c_cid.[description]`);
        } 
        else if (campo === 'cid_grupo') {
            const cidGroupSql = `CASE WHEN c_cid.code_cid LIKE 'A%' OR c_cid.code_cid LIKE 'B%' THEN 'A00-B99 - Algumas doenças infecciosas e parasitárias' WHEN c_cid.code_cid LIKE 'C%' OR c_cid.code_cid LIKE 'D0%' OR c_cid.code_cid LIKE 'D1%' OR c_cid.code_cid LIKE 'D2%' OR c_cid.code_cid LIKE 'D3%' OR c_cid.code_cid LIKE 'D4%' THEN 'C00-D48 - Neoplasias (tumores)' WHEN c_cid.code_cid LIKE 'D5%' OR c_cid.code_cid LIKE 'D6%' OR c_cid.code_cid LIKE 'D7%' OR c_cid.code_cid LIKE 'D8%' THEN 'D50-D89 - Doenças do sangue e dos órgãos hematopoéticos' WHEN c_cid.code_cid LIKE 'E%' THEN 'E00-E90 - Doenças endócrinas, nutricionais e metabólicas' WHEN c_cid.code_cid LIKE 'F%' THEN 'F00-F99 - Transtornos mentais e comportamentais' WHEN c_cid.code_cid LIKE 'M%' THEN 'M00-M99 - Doenças do sistema osteomuscular e do tecido conjuntivo' WHEN c_cid.code_cid LIKE 'Z%' THEN 'Z00-Z99 - Fatores que influenciam o estado de saúde' ELSE 'Outros / Não Identificado' END`;
            selectCols.push(`${cidGroupSql} as Grupo_CID`); groupCols.push(cidGroupSql);
        }
    });

    if (hasMonthGroup && agrupadores.length === 1) {
        metricasSql = `COUNT(DISTINCT ${colunaCount}) as Qtd_Novos_Mes, SUM(COUNT(DISTINCT ${colunaCount})) OVER (ORDER BY MIN(us.[date_absence]) ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as ${nomeColuna}`;
    }

    const allSelects = [...selectCols, metricasSql].filter(Boolean).join(', ');
    const colunasGroup = groupCols.length > 0 ? 'GROUP BY ' + groupCols.join(', ') : '';
    const query = `SELECT TOP 100 ${allSelects} ${baseJoins} ${whereClause} ${colunasGroup} ORDER BY ${orderBy}`;

    return responder(query, "analise_saude");
}

