if (intencao === 'beneficio' || intencao === 'beneficios') {
    const isCessacao = logica.includes('cessar') || logica.includes('fim') || logica.includes('vencimento') || (filtros.resultado_pericia && filtros.resultado_pericia.toLowerCase().includes('cessado'));

    // 🚨 Detectors for specific scenarios
    const isAcidentario = filtros.tipo_afastamento === 'Acidente' || logica.includes('acident') || logica.includes('b91');
    const isAlteracaoEspecie = logica.includes('alteracao') || logica.includes('mudanca') || logica.includes('especie') && (logica.includes('alterada') || logica.includes('muda'));

  // 🚨 2. DETECÇÃO DE ESTOQUE (ATIVOS) vs FLUXO (NOVOS)
    // Se o usuário pedir "Ativos" ou "Hoje", mudamos a lógica temporal
    const isEstoqueBeneficio = 
        (filtros.status_beneficio && filtros.status_beneficio.toLowerCase().includes('ativo')) || 
        logica.includes('ativos') || 
        logica.includes('estoque') || 
        logica.includes('hoje') || logica.includes('atualmente') ||logica.includes('agora') ||
        logica.includes('total'); // Frequentemente "Total de benefícios B91" implica estoque ativo

    // Se estamos buscando "Ativos" por data, REMOVEMOS o filtro de texto 'Ativo'.
    // Motivo: O status no banco pode ser 'Deferido', 'Em Gozo' ou até 'Cessado' (mas foi ativo no período).
    if (isEstoqueBeneficio && filtros.status_beneficio && filtros.status_beneficio.toLowerCase() === 'ativo') {
        filtros.status_beneficio = null; 
    }

    let condicaoDataUB = '';  // Condição para tabela principal (user_benefit)
    let condicaoDataUCB = ''; // Condição para tabela de mudança (user_change_benefit)

    if (isEstoqueBeneficio) {
        // Lógica de ATIVOS (Estoque):
        // Começou ANTES do fim do mês E (Não acabou OU Acabou DEPOIS do início do mês)
        condicaoDataUB = ` AND ub.start_date <= EOMONTH('${dataFimISO}') AND (ub.end_date IS NULL OR ub.end_date >= '${dataInicioISO}') `;

        // Para conversão (B31 -> B91): Se a mudança ocorreu ANTES do fim do período, ele conta como B91 ativo
        condicaoDataUCB = ` AND ucb.date_change_benefit_type <= EOMONTH('${dataFimISO}') `;
    } else {
        // Lógica de NOVOS (Fluxo):
        // O evento (Início ou Fim) ocorreu DENTRO do mês
        const coluna = isCessacao ? 'ub.end_date' : 'ub.start_date';
        // 🚨 Se for busca por colaborador, remove o limite de data para encontrar o histórico
        if (filtros.colaborador || filtros.matricula) {
            condicaoDataUB = ``; 
            condicaoDataUCB = ``;
        } else {
            condicaoDataUB = ` AND ${coluna} BETWEEN '${dataInicioISO}' AND EOMONTH('${dataFimISO}') `;
            condicaoDataUCB = ` AND ucb.date_change_benefit_type BETWEEN '${dataInicioISO}' AND EOMONTH('${dataFimISO}') `;
        }
    }

    let baseJoins = `
        FROM [user_benefit] ub
        LEFT JOIN [benefit_type] bt ON ub.[benefitTypeIdBenefitType] = bt.[id_benefit_type]
        LEFT JOIN [benefit_status] bs ON ub.[benefitStatusIdBenefitStatus] = bs.[id_benefit_status]
        INNER JOIN [user_steps] us ON ub.[userStepsIdUserSteps] = us.[id_user_steps]
        INNER JOIN [employee] e ON us.[employeeIdEmployee] = e.[id_Employee]
        INNER JOIN [company] c_matriz ON e.[company_id] = c_matriz.[id]
        LEFT JOIN [company] c_filial ON e.[branch_id] = c_filial.[id]
        LEFT JOIN [position] p ON e.[position_id] = p.[id_position]
        LEFT JOIN [user] u ON e.[user_id] = u.[id_user]
        LEFT JOIN [user_gender] ug ON u.[gender_id] = ug.[id]
        LEFT JOIN [cost_center] cc ON e.[cost_center_id] = cc.[cost_center_id]
        -- 🚨 JOIN PARA DETECTAR MUDANÇA DE ESPÉCIE (CONVERSÃO)
        LEFT JOIN [user_change_benefit] ucb ON ub.[id_user_benefit] = ucb.[user_benefit_id] AND ucb.delete_datetime IS NULL
        LEFT JOIN [benefit_type] bt_change ON ucb.[change_benefit_type] = bt_change.[id_benefit_type]
        -- 🚨 JOIN PARA ACIDENTES (CAT)
        LEFT JOIN [work_accident_reporting] war ON us.[workAccidentIdWorkAccidentReporting] = war.[id_work_accident_reporting]
    `;

    let whereClause = `
        WHERE 1=1 AND ub.[delete] = 'N' 
        ${filtroEmpresaSql}
        ${filtroDepartamentoSql}
        ${filtros.filial ? filtroFilialHibrido(filtros.filial) : ''}
        ${filtros.cargo ? filtroTxt('p', 'cargo', filtros.cargo) : ''}
        ${filtros.sexo ? filtroTxt('ug', 'sexo', filtros.sexo) : ''}
        ${filtros.centro_de_custo ? filtroTxt('cc', 'centro_de_custo', filtros.centro_de_custo) : ''}
        ${filtroTxt('bs', 'status_beneficio', filtros.status_beneficio)}
        ${filtros.matricula ? `AND e.id_Employee = '${escapeSql(filtros.matricula)}'` : ''}
        ${filtros.colaborador ? filtroTxt('u', 'colaborador', filtros.colaborador) : ''}
    `;

    // 🚨 SCENARIO 1: ALTERAÇÃO DE ESPÉCIE (The one requested)
    if (isAlteracaoEspecie) {
        // Must have a record in user_change_benefit
        whereClause += ` AND ucb.id_user_change_benefit IS NOT NULL `;

        // Filter by the change date
        whereClause += condicaoDataUCB; // Usa data da mudança
    } 
    // 🚨 SCENARIO 2: ACIDENTÁRIO (Previously fixed)
    else if (isAcidentario) {
        // Busca B91 (Acidentário) ou que tenha CAT (war)
        whereClause += `
            AND (
                -- 1. Espécie Original é 91/92/93/94 E atende a data (Ativo ou Novo)
                (
                    bt.benefit_type_code IN ('91', '92', '93', '94') 
                    ${condicaoDataUB}
                )
                OR 
                -- 2. Espécie foi ALTERADA para 91/92/93/94 E a mudança é válida para a data
                (
                    bt_change.benefit_type_code IN ('91', '92', '93', '94')
                    ${condicaoDataUCB}
                    -- Se for lógica de ativo, garante que o benefício pai também está ativo
                    ${isEstoqueBeneficio ? condicaoDataUB : ''}
                )
                OR 
                -- 3. Tem CAT registrada E o benefício atende a data
                (
                    war.id_work_accident_reporting IS NOT NULL
                    ${condicaoDataUB}
                )
            )
        `;
    }
    // 🚨 SCENARIO 3: STANDARD (General Benefit Count)
    else {
        // Caso Geral (não acidentário)
        whereClause += condicaoDataUB;
        whereClause += ` ${filtroTxt('bt', 'tipo_beneficio', filtros.tipo_beneficio)} `;
    }

    const nomeColuna = 'Qtd_Beneficios';
    let agrupadores = filtros.agrupamento || [];
    let selectCols = [];
    let groupCols = [];
    let orderBy = `${nomeColuna} DESC`;

    if (isPrevisao) {
        orderBy = `MIN(ub.start_date) ASC`; // Ou data de alteração se for o caso
    }
    // Dynamic Select for Benefit Type (Original vs Changed)
    const selectTipoBeneficio = `
        COALESCE(bt_change.benefit_type_description, bt.benefit_type_description) as Tipo_Beneficio
    `;
    const groupTipoBeneficio = `
        COALESCE(bt_change.benefit_type_description, bt.benefit_type_description)
    `;

    agrupadores.forEach(a => {
        const campo = a.toLowerCase();
        if (campo === 'tipo_beneficio') { selectCols.push(selectTipoBeneficio); groupCols.push(groupTipoBeneficio); }
        else if (campo === 'status_beneficio') { selectCols.push(`bs.[description] as Status_Beneficio`); groupCols.push(`bs.[description]`); }
        else if (campo === 'filial') { selectCols.push(`COALESCE(c_filial.companyName, c_matriz.companyName) as Filial`); groupCols.push(`COALESCE(c_filial.companyName, c_matriz.companyName)`); }
        else if (campo === 'empresa') { selectCols.push(`c_matriz.[companyName] as Empresa`); groupCols.push(`c_matriz.[companyName]`); }
        else if (campo === 'sexo') { selectCols.push(`ug.[label] as Sexo`); groupCols.push(`ug.[label]`); }
        else if (campo === 'cargo') { selectCols.push(`p.[position_name] as Cargo`); groupCols.push(`p.[position_name]`); }
        else if (campo === 'centro_de_custo') { selectCols.push(`cc.[name] as Centro_de_Custo`); groupCols.push(`cc.[name]`); }
      // 🚨 NOVA REGRA NO BLOCO B: Adiciona Nome e CPF
        else if (campo === 'colaborador' || campo === 'usuario') { 
            selectCols.push(`u.[name] as Colaborador`, `u.[cpf] as CPF`); 
            groupCols.push(`u.[name]`, `u.[cpf]`); 
        }
    });

    const colunasSelect = selectCols.length > 0 ? selectCols.join(', ') + ',' : '';
    const colunasGroup = groupCols.length > 0 ? 'GROUP BY ' + groupCols.join(', ') : '';

    let metricasSql = ``;

    // 🚨 LÓGICA DE LISTAGEM: Se pediu colaborador, lista os nomes. Se não, conta/faz média.
    // 🚨 LÓGICA DE LISTAGEM ENRIQUECIDA (BLOCO B): Traz dados de benefício completos
    if (agrupadores.includes('colaborador')) {
        metricasSql = `
            MAX(p.[position_name]) as Cargo, 
            FORMAT(MAX(ub.[start_date]), 'dd/MM/yyyy') as Data_Inicio_Beneficio,
            FORMAT(MAX(ub.[end_date]), 'dd/MM/yyyy') as Data_Fim_Beneficio,
            MAX(bs.[description]) as Status_Beneficio,
            FORMAT(MAX(us.[date_absence]), 'dd/MM/yyyy') as Data_Afastamento_Original,
            MAX(COALESCE(bt_change.benefit_type_description, bt.benefit_type_description)) as Tipo_Beneficio
        `;
        orderBy = `u.[name] ASC`; 
    }
    else {
        if (filtros.tipo_calculo === 'tempo_medio' || logica.includes('tempo') || logica.includes('duracao') || logica.includes('media')) {
            const formulaMedia = `CAST(AVG(CAST(DATEDIFF(day, ub.start_date, COALESCE(ub.end_date, GETDATE())) AS FLOAT)) / 30.44 AS DECIMAL(10,2))`;
            metricasSql = `${formulaMedia} as Media_Meses_Duracao`;
            orderBy = `${formulaMedia} DESC`;
        } else {
            metricasSql = `COUNT(DISTINCT ub.benefit_number) as Qtd_Beneficios`;
        }
    }

    const query = `SELECT TOP 100 ${colunasSelect} ${metricasSql} ${baseJoins} ${whereClause} ${colunasGroup} ORDER BY ${orderBy}`;

    return responder(query, "analise_beneficio");
}

